int a[100001];

int main()
{
	int n,b;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	for(int i=1;i<=n;i++)
	{
		int s=0;
		for(int j=1;j<=sqrt(a[i]);j++)
		{
			if(j*j*j*j==a[i])
			{
				s=1;
				printf("%d\n",j);
				break;
			}
		}
		if(s==0)
		{
			printf("-1\n");
		}
	}
